	let titleTag = false;
	let metaTag = false;
	let linkTag = false;
	let scriptTag = false;
	html.split('<head>')[1].split('</head>')[0]
		.split('<title>')[1].split('</title>')[0]
		.split('<meta ')[1].split('</meta>')[0]
		.split('<link ')[1].split('</link>')[0]
		.split('<script ')[1].split('</script>')[0]
